function solve(m: number, n: number, waitCost: number[][]): number {
    // Directions: right (0, 1), down (1, 0)
    const directions = [(0, 1), (1, 0)];

    // Priority queue: (total_cost, time, i, j)
    const pq: [number, number, number, number][] = [(1, 0, 0, 0)];
    // Visited matrix to keep track of the minimum cost to reach each cell at each time
    // Since time can be large, we use a dictionary to store the minimum cost for each (i, j)
    const visited: Map<string, number> = new Map();

    while (pq.length > 0) {
        const [totalCost, time, i, j] = pq.shift() as [number, number, number, number];

        // If we reach the destination, return the total cost
        if (i === m - 1 && j === n - 1) {
            return totalCost;
        }

        // Check if we have already visited this cell with a lower or equal cost
        const key = `${i},${j}`;
        if (visited.has(key) && visited.get(key) <= totalCost) {
            continue;
        }

        visited.set(key, totalCost);

        // If current time is odd (1-based), we can move right or down
        if (time % 2 === 1) {
            for (const [dx, dy] of directions) {
                const ni = i + dx;
                const nj = j + dy;
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    // Calculate the cost to enter the new cell
                    const enterCost = (ni + 1) * (nj + 1);
                    const newTotalCost = totalCost + enterCost;
                    pq.push([newTotalCost, time + 1, ni, nj]);
                }
            }
        } else {
            // If current time is even, we must wait
            const waitCostVal = waitCost[i][j];
            const newTotalCost = totalCost + waitCostVal;
            pq.push([newTotalCost, time + 1, i, j]);
        }
    }

    // If we reach here, no path was found (should not happen for valid inputs)
    return -1;
}
